    tour_complete_message: '🎉 Kuongoza kumekamilika! Sasa unaweza kuchunguza programu kikamilifu.',

    tour_step0_title: 'Karibu kwenye Mfumo',
    tour_step0_desc: 'Karibu! Ziara hii itakuelekeza katika kila kipengele cha mfumo wako mpya wa usimamizi. Bofya "Ijayo" kuanza.',

    tour_step1_title: 'Utambulisho wako wa Biashara',
    tour_step1_desc: 'Nembo yako inaonekana hapa. Unaweza kubadilisha hii baadaye katika Mipangilio ya Biashara.',

    tour_step2_title: 'Kituo cha Arifa',
    tour_step2_desc: 'Arifa za hisa chache na ujumbe wa mfumo zinaonekana hapa.',

    tour_step3_title: 'Dashibodi ya Haraka',
    tour_step3_desc: 'Fikia vikumbusho vyako vya kila siku, afya ya mfumo, na ukaguzi wa kasi ya muunganisho hapa.',

    tour_step4_title: 'Usimamizi wa Hisa',
    tour_step4_desc: 'Hebu tuanze na Hesabu. Bofya kitufe hiki kufungua menyu ya Chaguzi za Hisa.',

    tour_step5_title: 'Menyu ya Hisa',
    tour_step5_desc: 'Hiki ni kituo chako cha amri ya hesabu. Vitendo vyote vinavyohusiana na hisa viko hapa.',

    tour_step6_title: 'Ongeza Kipengee Kipya',
    tour_step6_desc: 'Bofya hapa kusajili bidhaa au huduma mpya kwenye mfumo.',

    tour_step7_title: 'Fomu ya Kuongeza Kipengee',
    tour_step7_desc: 'Jaza maelezo ya bidhaa yako mpya hapa.',

    tour_step8_title: 'Jina la Bidhaa',
    tour_step8_desc: 'Ingiza jina la kipengee (mf., "Kipanya kisichotumia waya").',

    tour_step9_title: 'Kategoria',
