    tour_step10_title: 'Hisa ya Awali',
    tour_step10_desc: 'Una kiasi gani sasa hivi?',

    tour_step11_title: 'Bei ya Kuuza',
    tour_step11_desc: 'Bei unayouzia.',

    tour_step12_title: 'Bei ya Gharama',
    tour_step12_desc: 'Bei uliyonunulia. Muhimu kwa kukokotoa faida baadaye.',

    tour_step13_title: 'Picha ya Bidhaa',
    tour_step13_desc: 'Pakia picha ili kurahisisha kutambua vitu wakati wa mauzo.',

    tour_step14_title: 'Hifadhi Kipengee',
    tour_step14_desc: 'Bofya hii kuhifadhi bidhaa kwenye hifadhidata yako.',

    tour_step15_title: 'Rudi Nyuma',
    tour_step15_desc: 'Umemaliza kuongeza? Bofya mshale huu kurudi kwenye menyu ya Chaguzi za Hisa.',

    tour_step16_title: 'Hisa ya Sasa',
    tour_step16_desc: 'Bofya hapa kutazama na kusimamia kile ulicho nacho kwenye duka kwa sasa.',

    tour_step17_title: 'Orodha ya Hesabu',
    tour_step17_desc: 'Ona vitu vyako vyote vilivyoorodheshwa hapa pamoja na idadi ya moja kwa moja.',

    tour_step18_title: 'Utafutaji Mahiri',
    tour_step18_desc: 'Andika jina hapa kuchuja orodha papo hapo.',

    tour_step19_title: 'Vichujio',
    tour_step19_desc: 'Chuja kwa "Hisa Chache" ili kuona kinachohitaji kuagizwa upya mara moja.',

    tour_step20_title: 'Chapisha Ripoti',
    tour_step20_desc: 'Tengeneza ripoti ya PDF ya hesabu yako ya sasa.',

    tour_step21_title: 'Jedwali la Hisa *bofya kwenye kipengee kipya ulichoongeza ili kuona maelezo zaidi*',
    tour_step21_desc: 'Ona data muhimu kwa mtazamo: idadi, bei za uniti, thamani ya jumla, na faida kwa kila bidhaa. bofya kwenye kipengee kuona maelezo zaidi',

    tour_step22_title: 'Njia ya Mkato ya Kujaza Hisa',
    tour_step22_desc: 'Ongeza kwa haraka viwango vya hesabu wakati shehena mpya zinapowasili bila kuhariri wasifu mzima wa bidhaa.',

    tour_step23_title: 'Hariri Maelezo',
    tour_step23_desc: 'Sasisha majina ya bidhaa, kategoria, au maelezo ya bei. Mabadiliko yoyote yataonekana mara moja kwenye mfumo mzima.',

    tour_step24_title: 'Zana za Uuzaji',
    tour_step24_desc: 'Tengeneza kiotomatiki picha za matangazo kwa kipengee hiki mahususi ili kushiriki kwenye mitandao ya kijamii.',

    tour_step25_title: 'Ufuatiliaji Dijitali',
    tour_step25_desc: 'Kila kipengee kina msimbo wa kipekee wa QR. Skana hii wakati wa mauzo kwa malipo ya haraka sana. bofya hapa kutengeneza msimbo wako wa QR wa bidhaa na ubandike kwenye mwili wa bidhaa tafadhali',

    tour_step26_title: 'Kituo cha Kudhibiti QR',
